  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useHUD } from '../../hooks/use_hud';
 10→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 11→import { useNavigation } from '../../hooks/use_navigation';
 12→import { copyToClipboard } from '../../utils/clipboard';
 13→import { fuzzyMatch } from '../../utils/fuzzy_search';
 14→import { isStringArray, storageGet, storageSet } from '../../utils/storage';
 15→import { ActionPanel } from '../action_panel/action_panel';
 16→import { CopyHUDIcon } from '../action_panel/actions/copy_to_clipboard';
 17→import type { DropdownSection } from '../action_panel/actions_dropdown';
 18→import { EmptyState } from '../empty_state/empty_state';
 19→import { HUDContainer } from '../hud/hud_container';
 20→import { Kbd } from '../kbd/kbd';
 21→import { SearchBar } from '../search_bar/search_bar';
 22→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 23→import { SearchDropdown } from '../search_bar/search_dropdown';
 24→import './emoji_picker_view.scss';
 25→
 26→const COLUMNS = 6;
 27→const STORAGE_KEY = 'emoji-recent';
 28→const MAX_RECENT = 12;
 29→
 30→function SearchEmptyIcon() {
 31→  return (
 32→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 33→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 34→      <line
 35→        x1="30"
 36→        y1="30"
 37→        x2="42"
 38→        y2="42"
 39→        stroke="currentColor"
 40→        strokeWidth="3"
 41→        strokeLinecap="round"
 42→      />
 43→    </svg>
 44→  );
 45→}
 46→
 47→function loadRecentEmojis(): string[] {
 48→  const stored = storageGet(STORAGE_KEY, isStringArray);
 49→  if (stored) return stored;
 50→
 51→  try {
 52→    const legacy = localStorage.getItem('emoji-picker-recent');
 53→    if (legacy) {
 54→      const parsed: unknown = JSON.parse(legacy);
 55→      if (isStringArray(parsed)) {
 56→        storageSet(STORAGE_KEY, parsed);
 57→        localStorage.removeItem('emoji-picker-recent');
 58→        return parsed;
 59→      }
 60→    }
 61→  } catch {
 62→    // unavailable
 63→  }
 64→  return [];
 65→}
 66→
 67→interface EmojiSection {
 68→  title: string;
 69→  emojis: EmojiEntry[];
 70→}
 71→
 72→const FILTER_SECTIONS: SearchDropdownSection[] = [
 73→  {
 74→    options: [
 75→      {
 76→        label: 'All',
 77→        value: 'all',
 78→      },
 79→    ],
 80→  },
 81→  {
 82→    title: 'Category',
 83→    options: EMOJI_CATEGORIES.map(c => ({
 84→      label: c.label,
 85→      value: c.value,
 86→    })),
 87→  },
 88→];
 89→
 90→export function EmojiPickerView() {
 91→  const nav = useNavigation();
 92→  const [query, setQuery] = useState('');
 93→  const [filterValue, setFilterValue] = useState('all');
 94→  const [activeIndex, setActiveIndex] = useState(0);
 95→  const [actionsOpen, setActionsOpen] = useState(false);
 96→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
 97→  const { items: hudItems, show: showHUD } = useHUD();
 98→  const containerRef = useRef<HTMLDivElement>(null);
 99→
100→  const emojiLookup = useMemo(() => {
101→    const map = new Map<string, EmojiEntry>();
102→    for (const e of MOCK_EMOJIS) {
103→      map.set(e.char, e);
104→    }
105→    return map;
106→  }, []);
107→
108→  const recentEmojis = useMemo(
109→    () =>
110→      recentChars
111→        .map(char => emojiLookup.get(char))
112→        .filter((e): e is EmojiEntry => e !== undefined),
113→    [
114→      recentChars,
115→      emojiLookup,
116→    ],
117→  );
118→
119→  const filtered = useMemo(() => {
120→    let emojis = MOCK_EMOJIS;
121→    if (filterValue !== 'all') {
122→      emojis = emojis.filter(e => e.category === filterValue);
123→    }
124→    if (query) {
125→      emojis = emojis.filter(
126→        e =>
127→          fuzzyMatch(query, e.name) ||
128→          e.keywords.some(k => fuzzyMatch(query, k)) ||
129→          e.char === query,
130→      );
131→    }
132→    return emojis;
133→  }, [
134→    query,
135→    filterValue,
136→  ]);
137→
138→  const sections = useMemo(() => {
139→    const result: EmojiSection[] = [];
140→
141→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
142→      result.push({
143→        title: 'Recently Used',
144→        emojis: recentEmojis,
145→      });
146→    }
147→
148→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
149→    for (const emoji of filtered) {
150→      const existing = grouped.get(emoji.category);
151→      if (existing) {
152→        existing.push(emoji);
153→      } else {
154→        grouped.set(emoji.category, [emoji]);
155→      }
156→    }
157→
158→    for (const cat of EMOJI_CATEGORY_ORDER) {
159→      const items = grouped.get(cat);
160→      if (items && items.length > 0) {
161→        result.push({
162→          title: EMOJI_CATEGORY_LABELS[cat],
163→          emojis: items,
164→        });
165→      }
166→    }
167→
168→    return result;
169→  }, [
170→    filtered,
171→    query,
172→    filterValue,
173→    recentEmojis,
174→  ]);
175→
176→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
177→  const totalCount = flatEmojis.length;
178→
179→  useEffect(() => {
180→    if (totalCount === 0) {
181→      setActiveIndex(0);
182→    } else if (activeIndex >= totalCount) {
183→      setActiveIndex(totalCount - 1);
184→    }
185→  }, [
186→    totalCount,
187→    activeIndex,
188→  ]);
189→
190→  useEffect(() => {
191→    const container = containerRef.current;
192→    if (!container) return;
193→    const el = container.querySelector<HTMLElement>(
194→      `[data-emoji-index="${activeIndex}"]`,
195→    );
196→    el?.scrollIntoView({ block: 'nearest' });
197→  }, [activeIndex]);
198→
199→  const selectedEmoji = flatEmojis[activeIndex];
200→
201→  const addToRecent = useCallback((char: string) => {
202→    setRecentChars(prev => {
203→      const next = [
204→        char,
205→        ...prev.filter(c => c !== char),
206→      ].slice(0, MAX_RECENT);
207→      storageSet(STORAGE_KEY, next);
208→      return next;
209→    });
210→  }, []);
211→
212→  const handleCopyEmoji = useCallback(
213→    (emoji?: EmojiEntry) => {
214→      const target = emoji ?? selectedEmoji;
215→      if (!target) return;
216→      copyToClipboard(target.char).catch(() => {});
217→      setActionsOpen(false);
218→      addToRecent(target.char);
219→      showHUD({
220→        icon: <CopyHUDIcon />,
221→        title: `Copied ${target.char}`,
222→      });
223→    },
224→    [
225→      selectedEmoji,
226→      showHUD,
227→      addToRecent,
228→    ],
229→  );
230→
231→  const handleQueryChange = useCallback((value: string) => {
232→    setQuery(value);
233→    setActiveIndex(0);
234→    setActionsOpen(false);
235→  }, []);
236→
237→  const handleFilterChange = useCallback((value: string) => {
238→    setFilterValue(value);
239→    setActiveIndex(0);
240→  }, []);
241→
242→  const toggleActions = useCallback(() => {
243→    setActionsOpen(prev => !prev);
244→  }, []);
245→
246→  const closeActions = useCallback(() => {
247→    setActionsOpen(false);
248→  }, []);
249→
250→  useKeyboardShortcut(
251→    {
252→      key: 'k',
253→      meta: true,
254→    },
255→    toggleActions,
256→  );
257→  useKeyboardShortcut(
258→    {
259→      key: 'c',
260→      meta: true,
261→    },
262→    () => handleCopyEmoji(),
263→  );
264→
265→  useEffect(() => {
266→    function handleKeyDown(e: KeyboardEvent) {
267→      if (totalCount === 0) return;
268→      if (actionsOpen) return;
269→      if (e.metaKey || e.ctrlKey || e.altKey) return;
270→
271→      const isTextInput =
272→        e.target instanceof HTMLInputElement ||
273→        e.target instanceof HTMLTextAreaElement;
274→
275→      switch (e.key) {
276→        case 'ArrowRight': {
277→          if (isTextInput) return;
278→          e.preventDefault();
279→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
280→          break;
281→        }
282→        case 'ArrowLeft': {
283→          if (isTextInput) return;
284→          e.preventDefault();
285→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
286→          break;
287→        }
288→        case 'ArrowDown': {
289→          e.preventDefault();
290→          setActiveIndex(prev => {
291→            const sectionInfo = getSectionInfo(prev);
292→            if (!sectionInfo) return prev;
293→            const { sectionStart, sectionLength } = sectionInfo;
294→            const posInSection = prev - sectionStart;
295→            const row = Math.floor(posInSection / COLUMNS);
296→            const col = posInSection % COLUMNS;
297→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
298→
299→            if (row + 1 < sectionRows) {
300→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
301→              return nextIdx < sectionStart + sectionLength
302→                ? nextIdx
303→                : sectionStart + sectionLength - 1;
304→            }
305→
306→            const nextSectionStart = sectionStart + sectionLength;
307→            if (nextSectionStart < totalCount) {
308→              const nextInfo = getSectionInfo(nextSectionStart);
309→              if (!nextInfo) return prev;
310→              const targetIdx = nextSectionStart + col;
311→              return targetIdx < nextSectionStart + nextInfo.sectionLength
312→                ? targetIdx
313→                : nextSectionStart + nextInfo.sectionLength - 1;
314→            }
315→
316→            return prev;
317→          });
318→          break;
319→        }
320→        case 'ArrowUp': {
321→          e.preventDefault();
322→          setActiveIndex(prev => {
323→            const sectionInfo = getSectionInfo(prev);
324→            if (!sectionInfo) return prev;
325→            const { sectionStart } = sectionInfo;
326→            const posInSection = prev - sectionStart;
327→            const row = Math.floor(posInSection / COLUMNS);
328→            const col = posInSection % COLUMNS;
329→
330→            if (row > 0) {
331→              return sectionStart + (row - 1) * COLUMNS + col;
332→            }
333→
334→            if (sectionStart > 0) {
335→              const prevSectionEnd = sectionStart - 1;
336→              const prevInfo = getSectionInfo(prevSectionEnd);
337→              if (!prevInfo) return prev;
338→              const prevSectionRows = Math.ceil(
339→                prevInfo.sectionLength / COLUMNS,
340→              );
341→              const lastRowStart =
342→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
343→              const targetIdx = lastRowStart + col;
344→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
345→                ? targetIdx
346→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
347→            }
348→
349→            return prev;
350→          });
351→          break;
352→        }
353→        case 'Enter': {
354→          e.preventDefault();
355→          handleCopyEmoji();
356→          break;
357→        }
358→      }
359→    }
360→
361→    window.addEventListener('keydown', handleKeyDown);
362→    return () => window.removeEventListener('keydown', handleKeyDown);
363→  }, [
364→    totalCount,
365→    actionsOpen,
366→    handleCopyEmoji,
367→    sections,
368→  ]);
369→
370→  const sectionBoundaries = useMemo(() => {
371→    const boundaries: {
372→      start: number;
373→      length: number;
374→    }[] = [];
375→    let offset = 0;
376→    for (const section of sections) {
377→      boundaries.push({
378→        start: offset,
379→        length: section.emojis.length,
380→      });
381→      offset += section.emojis.length;
382→    }
383→    return boundaries;
384→  }, [sections]);
385→
386→  function getSectionInfo(index: number) {
387→    for (const b of sectionBoundaries) {
388→      if (index >= b.start && index < b.start + b.length) {
389→        return {
390→          sectionStart: b.start,
391→          sectionLength: b.length,
392→        };
393→      }
394→    }
395→    return null;
396→  }
397→
398→  const dropdownSections: DropdownSection[] = useMemo(
399→    () => [
400→      {
401→        title: 'Actions',
402→        actions: [
403→          {
404→            label: 'Copy Emoji',
405→            shortcut: <Kbd keys={['↵']} />,
406→            onClick: () => handleCopyEmoji(),
407→          },
408→          {
409→            label: 'Copy to Clipboard',
410→            shortcut: (
411→              <Kbd
412→                keys={[
413→                  '⌘',
414→                  'C',
415→                ]}
416→              />
417→            ),
418→            onClick: () => handleCopyEmoji(),
419→          },
420→        ],
421→      },
422→    ],
423→    [handleCopyEmoji],
424→  );
425→
426→  const handleGridMouseOver = useCallback((
427→    e: React.MouseEvent<HTMLDivElement>,
428→  ) => {
429→    const target = (e.target as HTMLElement).closest<HTMLElement>(
430→      '[data-emoji-index]',
431→    );
432→    if (!target) return;
433→    const idx = Number(target.dataset.emojiIndex);
434→    if (!Number.isNaN(idx)) {
435→      setActiveIndex(idx);
436→    }
437→  }, []);
438→
439→  const activeDescendantId =
440→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
441→
442→  return (
443→    <>
444→      <SearchBar
445→        value={query}
446→        onChange={handleQueryChange}
447→        placeholder="Search Emoji..."
448→        activeDescendantId={activeDescendantId}
449→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
450→        dropdown={
451→          <SearchDropdown
452→            sections={FILTER_SECTIONS}
453→            value={filterValue}
454→            onChange={handleFilterChange}
455→          />
456→        }
457→      />
458→      <div className="command-palette__body">
459→        <div className="command-palette__list-container">
460→          {totalCount === 0 ? (
461→            <EmptyState
462→              icon={<SearchEmptyIcon />}
463→              title="No Emoji Found"
464→              description={
465→                query
466→                  ? 'Try a different search term'
467→                  : 'No emojis in this category'
468→              }
469→            />
470→          ) : (
