333→            })
334→          }
335→          options={WINDOW_WIDTH_OPTIONS}
336→        />
337→        <FormDropdown
338→          label="Font Size"
339→          value={settings.fontSize}
340→          onChange={v =>
341→            onSettingsChange({
342→              ...settings,
343→              fontSize: v,
344→            })
345→          }
346→          options={FONT_SIZE_OPTIONS}
347→        />
348→        <FormSeparator />
349→        <FormCheckbox
350→          label="Show Recent Applications"
351→          checked={settings.showRecentApps}
352→          onChange={v =>
353→            onSettingsChange({
354→              ...settings,
355→              showRecentApps: v,
356→            })
357→          }
358→          description="Display recently used apps in the root search"
359→        />
360→        <FormCheckbox
361→          label="Show Dock Apps"
362→          checked={settings.showDock}
